// Core interfaces for the Muon desktop application

export interface WindowData {
  id: string;
  x: number;
  y: number;
  w: number;
  h: number;
  url: string;
  viewId?: number;
}

export interface Transform {
  scale: number;
  x: number;
  y: number;
}

export interface DesktopState {
  windows: WindowData[];
  transform: Transform;
}

export interface ZoomState {
  zoomed: boolean;
  origScale: number;
  origOffsetX: number;
  origOffsetY: number;
}

export interface DragState {
  isDragging: boolean;
  startX: number;
  startY: number;
  startLeft: number;
  startTop: number;
}

export interface ViewportDimensions {
  width: number;
  height: number;
}

export interface WindowBounds {
  left: number;
  top: number;
  width: number;
  height: number;
}

// Event handler types
export type WindowEventHandler = (windowElement: HTMLElement, windowData: WindowData) => void;
export type SaveHandler = () => void;
export type TransformHandler = () => void;

// Navigation button configuration
export interface NavButtonConfig {
  label: string;
  title: string;
  handler: () => void;
}

// Constants
export const CONSTANTS = {
  BAR_HEIGHT: 24,
  MIN_WINDOW_SIZE: { width: 200, height: 200 },
  ZOOM_LIMITS: { min: 0.25, max: 4 },
  ZOOM_INTENSITY: 0.001,
  ANIMATION_DURATION: 300,
  DEBOUNCE_DELAY: 150,
  DEFAULT_ZOOM_BASE: 800,
  WINDOW_MARGIN: 32,
  RESIZE_HANDLE_SIZE: { corner: 12, edge: 8 }
} as const;

// Error types
export class MuonError extends Error {
  constructor(message: string, public code?: string) {
    super(message);
    this.name = 'MuonError';
  }
}

export class WindowNotFoundError extends MuonError {
  constructor(windowId: string) {
    super(`Window with ID ${windowId} not found`, 'WINDOW_NOT_FOUND');
  }
}

export class StateLoadError extends MuonError {
  constructor(originalError: unknown) {
    super(`Failed to load application state: ${originalError}`, 'STATE_LOAD_ERROR');
  }
}

export class StateSaveError extends MuonError {
  constructor(originalError: unknown) {
    super(`Failed to save application state: ${originalError}`, 'STATE_SAVE_ERROR');
  }
}
