import { CONSTANTS } from '../../types/muon';

/**
 * Safely get element by ID with error handling
 */
export function getElementById(id: string): HTMLElement {
  const element = document.getElementById(id);
  if (!element) {
    throw new Error(`Element with ID '${id}' not found`);
  }
  return element;
}

/**
 * Safely query selector with error handling
 */
export function querySelector<T extends HTMLElement>(selector: string, parent: HTMLElement | Document = document): T | null {
  try {
    return parent.querySelector(selector) as T | null;
  } catch (error) {
    console.error(`Error querying selector '${selector}':`, error);
    return null;
  }
}

/**
 * Safely query all selectors with error handling
 */
export function querySelectorAll<T extends HTMLElement>(selector: string, parent: HTMLElement | Document = document): T[] {
  try {
    return Array.from(parent.querySelectorAll(selector)) as T[];
  } catch (error) {
    console.error(`Error querying all selectors '${selector}':`, error);
    return [];
  }
}

/**
 * Create element with type safety and error handling
 */
export function createElement<K extends keyof HTMLElementTagNameMap>(
  tagName: K,
  options?: {
    className?: string;
    id?: string;
    textContent?: string;
    title?: string;
    style?: Partial<CSSStyleDeclaration>;
    attributes?: Record<string, string>;
  }
): HTMLElementTagNameMap[K] {
  try {
    const element = document.createElement(tagName);
    
    if (options) {
      if (options.className) element.className = options.className;
      if (options.id) element.id = options.id;
      if (options.textContent) element.textContent = options.textContent;
      if (options.title) element.title = options.title;
      
      if (options.style) {
        Object.assign(element.style, options.style);
      }
      
      if (options.attributes) {
        Object.entries(options.attributes).forEach(([key, value]) => {
          element.setAttribute(key, value);
        });
      }
    }
    
    return element;
  } catch (error) {
    console.error(`Error creating element '${tagName}':`, error);
    throw new Error(`Failed to create element '${tagName}'`);
  }
}

/**
 * Create a navigation button with consistent styling
 */
export function createNavButton(
  label: string,
  title: string,
  handler: () => void
): HTMLButtonElement {
  const button = createElement('button', {
    textContent: label,
    title: title,
    className: 'muon-nav-btn bg-transparent border-none leading-none cursor-pointer',
    style: {
      fontSize: '14px',
      width: `${CONSTANTS.BAR_HEIGHT - 6}px`,
      height: `${CONSTANTS.BAR_HEIGHT - 6}px`,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      borderRadius: '4px',
      color: '#aaa',
      transition: 'color 0.15s, background 0.15s'
    }
  });

  // Add hover effects
  button.addEventListener('mouseenter', () => {
    button.style.color = '#fff';
    button.style.background = '#333';
  });

  button.addEventListener('mouseleave', () => {
    button.style.color = '#aaa';
    button.style.background = 'transparent';
  });

  button.addEventListener('click', (e) => {
    e.stopPropagation();
    try {
      handler();
    } catch (error) {
      console.error('Navigation button handler error:', error);
    }
  });

  return button;
}

/**
 * Create a draggable area element
 */
export function createDragArea(): HTMLDivElement {
  return createElement('div', {
    className: 'muon-drag-area',
    style: {
      flex: '1 1 0%',
      height: `${CONSTANTS.BAR_HEIGHT}px`,
      cursor: 'grab',
      userSelect: 'none',
      background: 'transparent'
    }
  });
}

/**
 * Create a close button for windows
 */
export function createCloseButton(onClose: () => void): HTMLButtonElement {
  const button = createElement('button', {
    textContent: '×',
    title: 'Remove window',
    className: 'muon-remove bg-transparent border-none leading-none cursor-pointer',
    style: {
      fontSize: '18px',
      width: `${CONSTANTS.BAR_HEIGHT - 4}px`,
      height: `${CONSTANTS.BAR_HEIGHT - 4}px`,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      marginRight: '2px',
      zIndex: '4'
    }
  });

  button.addEventListener('click', (e) => {
    e.stopPropagation();
    try {
      onClose();
    } catch (error) {
      console.error('Close button handler error:', error);
    }
  });

  return button;
}

/**
 * Create a URL input bar
 */
export function createUrlBar(initialUrl: string = ''): HTMLInputElement {
  return createElement('input', {
    className: 'muon-urlbar px-2 py-1 text-xs outline-none',
    attributes: {
      type: 'text',
      value: initialUrl
    },
    style: {
      flex: '1 1 0%',
      height: `${CONSTANTS.BAR_HEIGHT - 4}px`,
      fontSize: '12px',
      border: 'none',
      background: 'transparent',
      color: '#e5e5e5',
      marginRight: '2px',
      textOverflow: 'ellipsis',
      overflow: 'hidden',
      whiteSpace: 'nowrap'
    }
  });
}

/**
 * Create a webview element with proper configuration
 */
export function createWebview(url: string, windowId: string): Electron.WebviewTag {
  try {
    const webview = document.createElement('webview') as Electron.WebviewTag;
    webview.className = 'w-full';
    webview.src = url || 'https://www.google.com/search';
    webview.partition = `persist:muon-${windowId}`;
    
    Object.assign(webview.style, {
      position: 'absolute',
      left: '0',
      width: '100%',
      border: 'none',
      top: `${CONSTANTS.BAR_HEIGHT * 2}px`,
      height: `calc(100% - ${CONSTANTS.BAR_HEIGHT * 2}px)`,
      zIndex: '0'
    });

    return webview;
  } catch (error) {
    console.error('Error creating webview:', error);
    throw new Error('Failed to create webview element');
  }
}

/**
 * Safely remove element with error handling
 */
export function removeElement(element: Element | null): void {
  try {
    if (element && element.parentNode) {
      element.parentNode.removeChild(element);
    }
  } catch (error) {
    console.error('Error removing element:', error);
  }
}

/**
 * Safely append child with error handling
 */
export function appendChild(parent: HTMLElement, child: HTMLElement): void {
  try {
    parent.appendChild(child);
  } catch (error) {
    console.error('Error appending child:', error);
    throw new Error('Failed to append child element');
  }
}

/**
 * Get element bounds with error handling
 */
export function getElementBounds(element: HTMLElement): DOMRect | null {
  try {
    return element.getBoundingClientRect();
  } catch (error) {
    console.error('Error getting element bounds:', error);
    return null;
  }
}

/**
 * Parse CSS pixel value safely
 */
export function parsePixelValue(value: string): number {
  try {
    const parsed = parseFloat(value);
    return isNaN(parsed) ? 0 : parsed;
  } catch (error) {
    console.error('Error parsing pixel value:', error);
    return 0;
  }
}
