import { WindowData, CONSTANTS } from '../../types/muon';
import { 
  createElement, 
  createNavButton, 
  createDragArea, 
  createCloseButton, 
  createUrlBar, 
  createWebview,
  appendChild,
  querySelector
} from '../utils/dom';
import { resetZoomState } from '../utils/zoom';

export interface WindowComponents {
  container: HTMLElement;
  topBar: HTMLElement;
  addressBar: HTMLElement;
  webview: Electron.WebviewTag;
  urlInput: HTMLInputElement;
}

export interface WindowFactoryOptions {
  onWindowRemove: (windowId: string) => void;
  onWindowDrag: (windowElement: HTMLElement, windowData: WindowData) => void;
  onWindowZoom: (windowElement: HTMLElement) => void;
  onActiveWindowChange: (windowElement: HTMLElement) => void;
  onSave: () => void;
  scale: number;
}

/**
 * Factory class for creating window elements with all necessary components
 */
export class WindowFactory {
  private options: WindowFactoryOptions;

  constructor(options: WindowFactoryOptions) {
    this.options = options;
  }

  /**
   * Create a complete window element with all components
   */
  createWindow(windowData: WindowData, focusAddressBar = false): WindowComponents {
    try {
      const container = this.createWindowContainer(windowData);
      const topBar = this.createTopBar(container, windowData);
      const addressBar = this.createAddressBar(windowData);
      const webview = this.createWebviewComponent(windowData);
      
      // Get URL input from address bar
      const urlInput = querySelector<HTMLInputElement>('.muon-urlbar', addressBar);
      if (!urlInput) {
        throw new Error('URL input not found in address bar');
      }

      // Assemble the window
      appendChild(container, topBar);
      appendChild(container, addressBar);
      appendChild(container, webview);

      // Set up event handlers
      this.setupWindowEvents(container, windowData, webview, urlInput);
      this.setupNavigationButtons(topBar, webview);

      // Focus address bar if requested
      if (focusAddressBar) {
        setTimeout(() => urlInput.focus(), 0);
      }

      return {
        container,
        topBar,
        addressBar,
        webview,
        urlInput
      };
    } catch (error) {
      console.error('Error creating window:', error);
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      throw new Error(`Failed to create window: ${errorMessage}`);
    }
  }

  /**
   * Create the main window container
   */
  private createWindowContainer(windowData: WindowData): HTMLElement {
    return createElement('div', {
      className: 'muon-window absolute border rounded overflow-hidden shadow-lg',
      style: {
        left: windowData.x + 'px',
        top: windowData.y + 'px',
        width: windowData.w + 'px',
        height: windowData.h + 'px',
        transform: '',
        transformOrigin: 'top left',
        zIndex: '1'
      },
      attributes: {
        'data-id': windowData.id
      }
    });
  }

  /**
   * Create the top bar with navigation and controls
   */
  private createTopBar(container: HTMLElement, windowData: WindowData): HTMLElement {
    const topBar = createElement('div', {
      className: 'muon-topbar-container',
      style: {
        position: 'absolute',
        top: '0',
        left: '0',
        right: '0',
        height: `${CONSTANTS.BAR_HEIGHT}px`,
        display: 'flex',
        alignItems: 'center',
        zIndex: '3',
        background: '#23232a'
      }
    });

    // Add navigation controls container
    const navControls = createElement('div', {
      className: 'muon-nav-controls',
      style: {
        display: 'flex',
        alignItems: 'center',
        gap: '2px',
        marginLeft: '4px'
      }
    });

    // Add drag area
    const dragArea = createDragArea();
    this.setupDragHandler(dragArea, container, windowData);

    // Add close button
    const closeButton = createCloseButton(() => {
      this.removeWindow(container, windowData.id);
    });

    // Add double-click zoom handler to top bar
    topBar.addEventListener('dblclick', (e) => {
      e.preventDefault();
      e.stopPropagation();
      this.options.onWindowZoom(container);
    });

    appendChild(topBar, navControls);
    appendChild(topBar, dragArea);
    appendChild(topBar, closeButton);

    return topBar;
  }

  /**
   * Create the address bar
   */
  private createAddressBar(windowData: WindowData): HTMLElement {
    const addressBarContainer = createElement('div', {
      className: 'muon-urlbar-container',
      style: {
        position: 'absolute',
        top: `${CONSTANTS.BAR_HEIGHT}px`,
        left: '0',
        right: '0',
        height: `${CONSTANTS.BAR_HEIGHT}px`,
        display: 'flex',
        alignItems: 'center',
        zIndex: '2',
        background: '#23232a'
      }
    });

    const urlInput = createUrlBar(windowData.url);
    appendChild(addressBarContainer, urlInput);

    return addressBarContainer;
  }

  /**
   * Create the webview component
   */
  private createWebviewComponent(windowData: WindowData): Electron.WebviewTag {
    return createWebview(windowData.url, windowData.id);
  }

  /**
   * Setup navigation buttons in the top bar
   */
  private setupNavigationButtons(topBar: HTMLElement, webview: Electron.WebviewTag): void {
    try {
      const navControls = querySelector('.muon-nav-controls', topBar);
      if (!navControls) return;

      const backButton = createNavButton('←', 'Back', () => {
        if (webview) webview.goBack();
      });

      const forwardButton = createNavButton('→', 'Forward', () => {
        if (webview) webview.goForward();
      });

      const reloadButton = createNavButton('⟳', 'Reload', () => {
        if (webview) webview.reload();
      });

      const stopButton = createNavButton('⨉', 'Stop', () => {
        if (webview) webview.stop();
      });

      // Add buttons in order
      appendChild(navControls, backButton);
      appendChild(navControls, forwardButton);
      appendChild(navControls, reloadButton);
      appendChild(navControls, stopButton);
    } catch (error) {
      console.error('Error setting up navigation buttons:', error);
    }
  }

  /**
   * Setup window event handlers
   */
  private setupWindowEvents(
    container: HTMLElement,
    windowData: WindowData,
    webview: Electron.WebviewTag,
    urlInput: HTMLInputElement
  ): void {
    try {
      // URL input handlers
      urlInput.addEventListener('focus', () => {
        setTimeout(() => urlInput.select(), 0);
      });

      urlInput.addEventListener('click', (e) => {
        if (document.activeElement !== urlInput) {
          urlInput.focus();
          e.preventDefault();
        }
      });

      urlInput.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') {
          this.handleUrlNavigation(urlInput.value.trim(), windowData, webview);
        }
      });

      // Webview navigation handlers
      webview.addEventListener('did-navigate', () => {
        urlInput.value = webview.getURL();
        windowData.url = webview.getURL();
      });

      webview.addEventListener('did-navigate-in-page', () => {
        urlInput.value = webview.getURL();
        windowData.url = webview.getURL();
      });

      // Webview zoom adjustment
      webview.addEventListener('dom-ready', () => {
        this.adjustWebviewZoom(container, webview);
        
        // Set up webview click handler for active window tracking
        webview.addEventListener('mousedown', () => {
          this.options.onActiveWindowChange(container);
        });
      });

      // Window active state tracking
      this.setupActiveWindowTracking(container);

      // Double-click centering (excluding URL bar and resize handles)
      container.addEventListener('dblclick', (e) => {
        const target = e.target as HTMLElement;
        if (target.closest('.muon-urlbar') || target.closest('.muon-resize-handle')) {
          return;
        }
        e.stopPropagation();
        this.options.onWindowZoom(container);
      });

    } catch (error) {
      console.error('Error setting up window events:', error);
    }
  }

  /**
   * Handle URL navigation with smart URL processing
   */
  private handleUrlNavigation(url: string, windowData: WindowData, webview: Electron.WebviewTag): void {
    try {
      let processedUrl = url;
      
      if (!/^(https?:|file:)/i.test(url)) {
        if (/^[\w-]+\.[\w-]+/.test(url)) {
          processedUrl = 'https://' + url;
        } else {
          processedUrl = 'https://www.google.com/search?q=' + encodeURIComponent(url);
        }
      }

      windowData.url = processedUrl;
      webview.src = processedUrl;
    } catch (error) {
      console.error('Error handling URL navigation:', error);
    }
  }

  /**
   * Adjust webview zoom based on container width
   */
  private adjustWebviewZoom(container: HTMLElement, webview: Electron.WebviewTag): void {
    try {
      const newZoom = container.offsetWidth / CONSTANTS.DEFAULT_ZOOM_BASE;
      webview.setZoomFactor(newZoom);
    } catch (error) {
      console.error('Error adjusting webview zoom:', error);
    }
  }

  /**
   * Setup drag handling for window movement
   */
  private setupDragHandler(dragArea: HTMLElement, container: HTMLElement, windowData: WindowData): void {
    dragArea.addEventListener('mousedown', (e) => {
      if (e.button !== 0) return;
      
      try {
        e.preventDefault();
        e.stopPropagation();
        
        const startX = e.clientX;
        const startY = e.clientY;
        const startLeft = parseFloat(container.style.left);
        const startTop = parseFloat(container.style.top);

        const doDrag = (ev: MouseEvent) => {
          const dx = (ev.clientX - startX) / this.options.scale;
          const dy = (ev.clientY - startY) / this.options.scale;
          container.style.left = (startLeft + dx) + 'px';
          container.style.top = (startTop + dy) + 'px';
        };

        const stopDrag = (ev: MouseEvent) => {
          document.removeEventListener('mousemove', doDrag);
          document.removeEventListener('mouseup', stopDrag);
          
          // Save position if moved significantly
          if (Math.abs(ev.clientX - startX) > 2 || Math.abs(ev.clientY - startY) > 2) {
            windowData.x = parseFloat(container.style.left);
            windowData.y = parseFloat(container.style.top);
            this.options.onSave();
          }
        };

        document.addEventListener('mousemove', doDrag);
        document.addEventListener('mouseup', stopDrag);
      } catch (error) {
        console.error('Error in drag handler:', error);
      }
    });
  }

  /**
   * Setup active window tracking
   */
  private setupActiveWindowTracking(container: HTMLElement): void {
    const setActiveWindow = () => {
      this.options.onActiveWindowChange(container);
    };

    // Add event listeners for various interactions
    container.addEventListener('mousedown', setActiveWindow);
    
    const topBar = querySelector('.muon-topbar-container', container);
    const addressBar = querySelector('.muon-urlbar-container', container);
    const urlInput = querySelector('.muon-urlbar', container);

    if (topBar) topBar.addEventListener('mousedown', setActiveWindow);
    if (addressBar) addressBar.addEventListener('mousedown', setActiveWindow);
    if (urlInput) urlInput.addEventListener('mousedown', setActiveWindow);
  }

  /**
   * Remove a window and clean up resources
   */
  private removeWindow(container: HTMLElement, windowId: string): void {
    try {
      // Clean up zoom state
      resetZoomState(container);
      
      // Remove from DOM
      container.remove();
      
      // Notify parent of removal
      this.options.onWindowRemove(windowId);
    } catch (error) {
      console.error('Error removing window:', error);
    }
  }
}
